import json
import boto3

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    message_content = event.get('message_content')
    topic_arn = event.get('topic_arn')
    notification_type = event.get('notification_type', 'default') # 'default', 'sms', 'email', etc.
    subject = event.get('subject') # Optional, mainly for email

    if not message_content or not topic_arn:
        raise ValueError("Missing 'message_content' or 'topic_arn' in event data.")

    publish_params = {
        'TopicArn': topic_arn,
    }

    if notification_type == 'sms':
        # For SMS, the message is plain text
        publish_params['Message'] = message_content
        publish_params['MessageAttributes'] = {
            'AWS.SNS.SMS.SMSType': {
                'DataType': 'String',
                'StringValue': 'Transactional' # Or 'Promotional'
            }
        }
    elif notification_type == 'email':
        # For email, message can be raw or JSON. Subject is often used.
        publish_params['Message'] = message_content
        if subject:
            publish_params['Subject'] = subject
    else: # Default type, often treated as raw or JSON depending on topic subscription
        # If the message is intended for multiple subscription types (e.g., email, SQS, HTTP),
        # it's best practice to send a JSON message with different fields for each type.
        # For simplicity here, we'll send the raw message_content.
        # If you want to send a structured JSON for all types, uncomment and adjust:
        # publish_params['Message'] = json.dumps({
        #     'default': message_content,
        #     'email': message_content,
        #     'sms': message_content
        # })
        # publish_params['MessageStructure'] = 'json'
        # For now, just send the plain message. Subscribers will receive it as raw.
        publish_params['Message'] = message_content
        if subject: # Subject might be ignored by non-email subscribers, but useful for email
            publish_params['Subject'] = subject

    try:
        response = sns_client.publish(**publish_params)
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully!',
                'message_id': response['MessageId']
            })
        }
    except Exception as e:
        print(f"Error publishing message: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': f"Failed to publish message: {str(e)}"
            })
        }